'use client';

import AdminLayout from '@/components/AdminLayout';
import { useState } from 'react';

export default function ChannelsPage() {
    return (
        <AdminLayout>
            <div className="page-header">
                <div className="page-header-top">
                    <div>
                        <h1 className="page-title">Distribution Channels</h1>
                        <p className="page-subtitle">Configure and monitor your delivery channels</p>
                    </div>
                </div>
            </div>

            <div className="page-body">
                <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                    <ChannelCard
                        icon="📧"
                        name="Email (Mailchimp)"
                        description="Send full devotional with audio link via Mailchimp campaign"
                        status="not_configured"
                        details={[
                            { label: 'API Key', value: 'Not set', configured: false },
                            { label: 'List ID', value: 'Not set', configured: false },
                            { label: 'From Email', value: 'Not set', configured: false },
                        ]}
                    />

                    <ChannelCard
                        icon="💬"
                        name="WhatsApp Business"
                        description="Send daily summary + audio link via WhatsApp Business Cloud API"
                        status="not_configured"
                        details={[
                            { label: 'Access Token', value: 'Not set', configured: false },
                            { label: 'Phone Number ID', value: 'Not set', configured: false },
                            { label: 'Template', value: 'Not set', configured: false },
                        ]}
                    />

                    <ChannelCard
                        icon="📰"
                        name="Blog (Firebase → Wix)"
                        description="Auto-publish devotional posts, embedded in your Wix site"
                        status="not_configured"
                        details={[
                            { label: 'Firebase Hosting', value: 'Not deployed', configured: false },
                            { label: 'Wix Embed URL', value: 'Not set', configured: false },
                        ]}
                    />
                </div>
            </div>
        </AdminLayout>
    );
}

function ChannelCard({
    icon,
    name,
    description,
    status,
    details,
}: {
    icon: string;
    name: string;
    description: string;
    status: 'configured' | 'not_configured' | 'error';
    details: { label: string; value: string; configured: boolean }[];
}) {
    const [enabled, setEnabled] = useState(false);

    return (
        <div className="card">
            <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' }}>
                <div style={{ display: 'flex', gap: 16, flex: 1 }}>
                    <div style={{ fontSize: 32 }}>{icon}</div>
                    <div style={{ flex: 1 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 4 }}>
                            <div style={{ fontWeight: 700, fontSize: 16 }}>{name}</div>
                            <span className={`badge ${status === 'configured' ? 'badge-success' : 'badge-warning'}`}>
                                <span className="badge-dot"></span>
                                {status === 'configured' ? 'Configured' : 'Not Configured'}
                            </span>
                        </div>
                        <div style={{ fontSize: 13, color: 'var(--text-tertiary)', marginBottom: 16 }}>{description}</div>

                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 12 }}>
                            {details.map((d) => (
                                <div key={d.label} style={{
                                    padding: '10px 14px',
                                    background: 'var(--bg-input)',
                                    borderRadius: 'var(--radius-sm)',
                                    border: `1px solid ${d.configured ? 'rgba(34, 197, 94, 0.2)' : 'var(--border-subtle)'}`,
                                }}>
                                    <div style={{ fontSize: 10, fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--text-muted)', marginBottom: 4 }}>
                                        {d.label}
                                    </div>
                                    <div style={{ fontSize: 13, color: d.configured ? 'var(--text-primary)' : 'var(--text-muted)' }}>
                                        {d.value}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
                <label className="toggle" style={{ marginLeft: 16, flexShrink: 0 }}>
                    <input type="checkbox" checked={enabled} onChange={() => setEnabled(!enabled)} />
                    <span className="toggle-slider" />
                </label>
            </div>
        </div>
    );
}
